  1	import * as React from 'react';
  2	import {
  3	  Button,
  4	  ButtonVariant,
  5	  FormGroup,
  6	  FormHelperText,
  7	  FormSelect,
  8	  FormSelectOption,
  9	  HelperText,
 10	  HelperTextItem,
 11	  TextInput
 12	} from '@patternfly/react-core';
 13	import { IRow, Td, ThProps, Tr } from '@patternfly/react-table';
 14	import { isGatewayHostValid } from '../../../utils/IstioConfigUtils';
 15	import { ServerForm } from '../../../types/IstioObjects';
 16	import { isValid } from 'utils/Common';
 17	import { isValidPort } from './ListenerBuilder';
 18	import { kialiStyle } from 'styles/StyleUtils';
 19	import { KialiIcon } from 'config/KialiIcon';
 20	import { SimpleTable } from 'components/Table/SimpleTable';
 21	
 22	type ServerBuilderProps = {
 23	  index: number;
 24	  onChange: (serverform: ServerForm, i: number) => void;
 25	  onRemoveServer: (i: number) => void;
 26	  server: ServerForm;
 27	};
 28	
 29	const columns: ThProps[] = [
 30	  {
 31	    title: 'Port Number',
 32	    width: 20
 33	  },
 34	  {
 35	    title: 'Port Name',
 36	    width: 20
 37	  },
 38	  {
 39	    title: 'Protocol',
 40	    width: 20
 41	  }
 42	];
 43	
 44	export const protocols = ['HTTP', 'HTTPS', 'GRPC', 'HTTP2', 'MONGO', 'TCP', 'TLS'];
 45	const tlsModes = ['PASSTHROUGH', 'SIMPLE', 'MUTUAL', 'AUTO_PASSTHROUGH', 'ISTIO_MUTUAL', 'OPTIONAL_MUTUAL'];
 46	
 47	export const areValidHosts = (hosts: string[]): boolean => {
 48	  if (hosts.length === 0) {
 49	    return false;
 50	  }
 51	
 52	  let isValid = true;
 53	
 54	  for (let i = 0; i < hosts.length; i++) {
 55	    if (!isGatewayHostValid(hosts[i])) {
 56	      isValid = false;
 57	      break;
 58	    }
 59	  }
 60	
 61	  return isValid;
 62	};
 63	
 64	const tableStyle = kialiStyle({
 65	  $nest: {
 66	    '& tr': {
 67	      borderBottom: 0
 68	    },
 69	    '&& tbody td': {
 70	      padding: 0,
 71	      paddingRight: '0.5rem'
 72	    }
 73	  }
 74	});
 75	
 76	const deleteButtonStyle = kialiStyle({
 77	  display: 'flex',
 78	  margin: 'auto',
 79	  padding: '0.25rem'
 80	});
 81	
 82	export const ServerBuilder: React.FC<ServerBuilderProps> = (props: ServerBuilderProps) => {
 83	  const onAddHosts = (_event: React.FormEvent, value: string): void => {
 84	    const server = props.server;
 85	    server.hosts = value.trim().length === 0 ? [] : value.split(',').map(host => host.trim());
 86	
 87	    props.onChange(server, props.index);
 88	  };
 89	
 90	  const onAddPortNumber = (_event: React.FormEvent, value: string): void => {
 91	    const server = props.server;
 92	    server.number = value.trim();
 93	
 94	    props.onChange(server, props.index);
 95	  };
 96	
 97	  const onAddPortName = (_event: React.FormEvent, value: string): void => {
 98	    const server = props.server;
 99	    server.name = value.trim();
100	
101	    props.onChange(server, props.index);
102	  };
103	
104	  const onAddPortProtocol = (_event: React.FormEvent, value: string): void => {
105	    const server = props.server;
106	    server.protocol = value.trim();
107	
108	    props.onChange(server, props.index);
109	  };
110	
111	  const onAddTlsMode = (_event: React.FormEvent, value: string): void => {
112	    const server = props.server;
113	    server.tlsMode = value.trim();
114	
115	    props.onChange(server, props.index);
116	  };
117	
118	  const onAddTlsServerCertificate = (_event: React.FormEvent, value: string): void => {
119	    const server = props.server;
120	    server.tlsServerCertificate = value.trim();
121	
122	    props.onChange(server, props.index);
123	  };
124	
125	  const onAddTlsPrivateKey = (_event: React.FormEvent, value: string): void => {
126	    const server = props.server;
127	    server.tlsPrivateKey = value.trim();
128	
129	    props.onChange(server, props.index);
130	  };
131	
132	  const onAddTlsCaCertificate = (_event: React.FormEvent, value: string): void => {
133	    const server = props.server;
134	    server.tlsCaCertificate = value.trim();
135	
136	    props.onChange(server, props.index);
137	  };
138	
139	  const portRows: IRow[] = [
140	    {
141	      cells: [
142	        <TextInput
143	          value={props.server.number}
144	          type="text"
145	          id={`addPortNumber_${props.index}`}
146	          aria-describedby="add port number"
147	          name="addPortNumber"
148	          onChange={onAddPortNumber}
149	          validated={isValid(isValidPort(props.server.number))}
150	        />,
151	
152	        <TextInput
153	          value={props.server.name}
154	          type="text"
155	          id={`addPortName_${props.index}`}
156	          aria-describedby="add port name"
157	          name="addPortName"
158	          onChange={onAddPortName}
159	          validated={isValid(props.server.name.length > 0)}
160	        />,
161	
162	        <FormSelect
163	          value={props.server.protocol}
164	          id={`addPortProtocol_${props.index}`}
165	          name="addPortProtocol"
166	          onChange={onAddPortProtocol}
167	        >
168	          {protocols.map((option, index) => (
169	            <FormSelectOption isDisabled={false} key={`p_${index}`} value={option} label={option} />
170	          ))}
171	        </FormSelect>
172	      ]
173	    }
174	  ];
175	
176	  const showTls = props.server.protocol === 'HTTPS' || props.server.protocol === 'TLS';
177	
178	  return (
179	    <Tr>
180	      <Td>
181	        <FormGroup label="Hosts" isRequired={true} fieldId="gateway-selector">
182	          <TextInput
183	            value={props.server.hosts.join(',')}
184	            isRequired={true}
185	            type="text"
186	            id={`hosts_${props.index}`}
187	            aria-describedby="hosts"
188	            name="hosts"
189	            onChange={onAddHosts}
190	            validated={isValid(areValidHosts(props.server.hosts))}
191	          />
192	
193	          <FormHelperText>
194	            <HelperText>
195	              <HelperTextItem>
196	                {isValid(areValidHosts(props.server.hosts))
197	                  ? 'One or more hosts exposed by this Gateway.'
198	                  : 'Invalid hosts for this Gateway. Enter one or more hosts separated by comma.'}
199	              </HelperTextItem>
200	            </HelperText>
201	          </FormHelperText>
202	        </FormGroup>
203	
204	        <FormGroup label="Port" isRequired={true} fieldId="server-port" style={{ padding: '0.5rem 0' }}>
205	          <SimpleTable label="Port Level MTLS" className={tableStyle} columns={columns} rows={portRows} />
206	        </FormGroup>
207	
208	        {showTls && (
209	          <FormGroup label="TLS Mode" isRequired={true} fieldId="addTlsMode" style={{ margin: '0.5rem 0' }}>
210	            <FormSelect value={props.server.tlsMode} id="addTlsMode" name="addTlsMode" onChange={onAddTlsMode}>
211	              {tlsModes.map((option, index) => (
212	                <FormSelectOption isDisabled={false} key={`p_${index}`} value={option} label={option} />
213	              ))}
214	            </FormSelect>
215	          </FormGroup>
216	        )}
217	
218	        {showTls && (props.server.tlsMode === 'SIMPLE' || props.server.tlsMode === 'MUTUAL') && (
219	          <>
220	            <FormGroup
221	              label="Server Certificate"
222	              style={{ margin: '0.5rem 0' }}
223	              isRequired={true}
224	              fieldId="server-certificate"
225	            >
226	              <TextInput
227	                value={props.server.tlsServerCertificate}
228	                isRequired={true}
229	                type="text"
230	                id="server-certificate"
231	                aria-describedby="server-certificate"
232	                name="server-certificate"
233	                onChange={onAddTlsServerCertificate}
234	                validated={isValid(props.server.tlsServerCertificate.length > 0)}
235	              />
236	
237	              {!isValid(props.server.tlsServerCertificate.length > 0) && (
238	                <FormHelperText>
239	                  <HelperText>
240	                    <HelperTextItem>
241	                      The path to the file holding the server-side TLS certificate to use.
242	                    </HelperTextItem>
243	                  </HelperText>
244	                </FormHelperText>
245	              )}
246	            </FormGroup>
247	
248	            <FormGroup label="Private Key" isRequired={true} fieldId="private-key" style={{ margin: '0.5rem 0' }}>
249	              <TextInput
250	                value={props.server.tlsPrivateKey}
251	                isRequired={true}
252	                type="text"
253	                id="private-key"
254	                aria-describedby="private-key"
255	                name="private-key"
256	                onChange={onAddTlsPrivateKey}
257	                validated={isValid(props.server.tlsPrivateKey.length > 0)}
258	              />
259	
260	              {!isValid(props.server.tlsPrivateKey.length > 0) && (
261	                <FormHelperText>
262	                  <HelperText>
263	                    <HelperTextItem>The path to the file holding the server’s private key.</HelperTextItem>
264	                  </HelperText>
265	                </FormHelperText>
266	              )}
267	            </FormGroup>
268	          </>
269	        )}
270	
271	        {showTls && props.server.tlsMode === 'MUTUAL' && (
272	          <FormGroup label="CA Certificate" style={{ margin: '0.5rem 0' }} isRequired={true} fieldId="ca-certificate">
273	            <TextInput
274	              value={props.server.tlsCaCertificate}
275	              isRequired={true}
276	              type="text"
277	              id="ca-certificate"
278	              aria-describedby="ca-certificate"
279	              name="ca-certificate"
280	              onChange={onAddTlsCaCertificate}
281	              validated={isValid(props.server.tlsCaCertificate.length > 0)}
282	            />
283	
284	            {!isValid(props.server.tlsCaCertificate.length > 0) && (
285	              <FormHelperText>
286	                <HelperText>
287	                  <HelperTextItem>
288	                    The path to a file containing certificate authority certificates to use in verifying a presented
289	                    client side certificate.
290	                  </HelperTextItem>
291	                </HelperText>
292	              </FormHelperText>
293	            )}
294	          </FormGroup>
295	        )}
296	      </Td>
297	
298	      <Td style={{ verticalAlign: 'middle' }}>
299	        <Button
300	          id="deleteBtn"
301	          variant={ButtonVariant.link}
302	          icon={<KialiIcon.Trash />}
303	          className={deleteButtonStyle}
304	          onClick={() => props.onRemoveServer(props.index)}
305	        />
306	      </Td>
307	    </Tr>
308	  );
309	};

